function mergeCarts(localCart: CartItem[], remoteCart: CartItem[]): CartItem[] {
  const cartMap = new Map<string, CartItem>();

  // Ajouter tous les articles du panier distant
  remoteCart.forEach(item => {
    cartMap.set(item.productId, { ...item });
  });

  // Fusionner les articles du panier local
  localCart.forEach(localItem => {
    const existing = cartMap.get(localItem.productId);
    if (existing) {
      // Additionner les quantités
      existing.quantity += localItem.quantity;
    } else {
      cartMap.set(localItem.productId, { ...localItem });
    }
  });

  return Array.from(cartMap.values());
}
