function resolveCartConflict(localCart, remoteCart, lastSyncTimestamp) {
  // Détection de conflit : comparaison des versions
  const hasConflict = JSON.stringify(localCart) !== JSON.stringify(remoteCart);

  if (!hasConflict) return remoteCart;

  // Stratégie: Demander à l'utilisateur via un callback
  // Mais pour une fonction pure, on retourne un objet signalant le conflit
  return {
    status: 'CONFLICT',
    local: localCart,
    remote: remoteCart,
    resolution: 'USER_CHOICE'
  };
}

// Version avancée avec fusion automatique pour produits sans conflit
type ConflictResolution = 'KEEP_LOCAL' | 'KEEP_REMOTE' | 'MERGE' | 'ASK_USER';

function autoMergeCarts(local, remote, resolution: ConflictResolution) {
  switch(resolution) {
    case 'MERGE':
      const merged = [...remote];
      local.forEach(localItem => {
        const existing = merged.find(i => i.id === localItem.id);
        if(existing) existing.quantity += localItem.quantity;
        else merged.push(localItem);
      });
      return merged;
    case 'KEEP_LOCAL': return local;
    case 'KEEP_REMOTE': return remote;
    default: throw new Error('Résolution manuelle requise');
  }
}
