syncCartAfterLogin: async (userId, apiClient) => {
  const localItems = get().items;

  // ÉTAPE 2: Récupérer le panier distant
  const remoteCart = await apiClient.get(`/carts/${userId}`);
  const remoteItems = remoteCart.items || [];

  // ÉTAPE 3: Fusionner
  const mergedMap = new Map();

  // Ajouter les articles distants
  remoteItems.forEach(item => {
    mergedMap.set(item.productId, { ...item });
  });

  // Fusionner les articles locaux
  localItems.forEach(localItem => {
    const existing = mergedMap.get(localItem.productId);
    if (existing) {
      existing.quantity += localItem.quantity;
    } else {
      mergedMap.set(localItem.productId, { ...localItem });
    }
  });

  const mergedItems = Array.from(mergedMap.values());

  // ÉTAPE 4: Envoyer au backend
  await apiClient.put(`/carts/${userId}`, { items: mergedItems });

  // ÉTAPE 5: Mettre à jour le store
  set({ items: mergedItems });

  // ÉTAPE 6: Marquer comme authentifié
  set({ isGuestCart: false });

  // Optionnel: vider la persistence guest (le next render utilisera le nouveau state)
}
