async function retryPendingOperations(apiClient, queueStore, cartStore) {
  const pendingOps = queueStore.getPendingOperations();

  for (const op of pendingOps) {
    try {
      switch(op.type) {
        case 'ADD_TO_CART':
          await apiClient.post('/cart/add', { productId: op.productId, quantity: op.quantity });
          break;
        case 'UPDATE_QUANTITY':
          await apiClient.put('/cart/update', { productId: op.productId, quantity: op.quantity });
          break;
        case 'REMOVE_ITEM':
          await apiClient.delete(`/cart/item/${op.productId}`);
          break;
      }
      // Succès : retirer de la file
      queueStore.removeOperation(op.id);
    } catch (error) {
      if (error.response?.status === 409 || error.response?.status === 400) {
        // Conflit de stock ou indisponibilité
        const productName = error.response.data.productName;
        const userConfirmed = await showConflictDialog(
          `Le produit ${productName} n'est plus disponible. Retirer du panier ?`
        );
        if (userConfirmed) {
          cartStore.removeItem(op.productId);
          await apiClient.delete(`/cart/item/${op.productId}`);
          queueStore.removeOperation(op.id);
        }
      } else if (error.response?.status === 401) {
        // Token expiré : re-authentification
        await refreshToken();
        // Re-tenter l'opération après refresh (récursion ou boucle)
      } else {
        // Erreur réseau temporaire : conserver dans la file
        console.log('Réessai plus tard', error);
      }
    }
  }
}
